import puppeteer from 'puppeteer';

const sessionId = 'a059941d-503d-468f-94b5-fca2b62dc4f7';
const baseUrl = process.env.TARGET_BASE_URL ?? 'http://frontend:8566';
const url = baseUrl + '/sessions/' + sessionId + '?stage=audio';

const browser = await puppeteer.launch({
  headless: true,
  executablePath: process.env.PUPPETEER_EXECUTABLE_PATH,
  args: ['--no-sandbox', '--disable-setuid-sandbox'],
});

try {
  const page = await browser.newPage();
  await page.setViewport({ width: 1440, height: 960 });
  await page.goto(url, { waitUntil: 'networkidle2', timeout: 30000 });
  await page.waitForFunction(() => document.body?.innerText.includes('Approx. 14 min'), { timeout: 30000 });

  await page.evaluate(() => {
    const labels = [...document.querySelectorAll('label')];
    const playbackLabel = labels.find((label) => label.textContent?.includes('Playback speed')) ?? null;
    if (playbackLabel === null) {
      throw new Error('Playback speed label not found');
    }

    const inputId = playbackLabel.getAttribute('for');
    const input = inputId ? document.getElementById(inputId) : null;
    if (input instanceof HTMLInputElement === false) {
      throw new Error('Playback speed range input not found');
    }

    const descriptor = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value');
    descriptor?.set?.call(input, '0.85');
    input.dispatchEvent(new Event('input', { bubbles: true }));
    input.dispatchEvent(new Event('change', { bubbles: true }));
  });

  await page.waitForTimeout(1000);
  const bodyText = await page.evaluate(() => document.body?.innerText || '');
  console.log(bodyText);
} finally {
  await browser.close();
}
